def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            base = np.exp(-ratio * 12)
            factor = 1.1
            for a in range(1, 15):
                val = base * (a ** 3) * np.sin(a * ratio * 10)
                if a % 2 == 0:
                    val *= 1.04
                else:
                    val *= 0.97
                score += val * factor
                factor *= 0.98
            if ((capacity + item) % 4 == 0) or ((capacity - item) % 7 == 0):
                score *= 0.82
            if score > 10:
                score /= 3.1
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 3):
                prod *= (ratio + (n ** 0.5) / (n + 2))
                if prod > 5e5:
                    prod = np.log1p(prod)
                    break
            mod_val = int(prod * 7) % 250
            base_score = np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 8 == 0) and ((item * 3) % 4 == 0):
                base_score += 5.7
            else:
                base_score -= 1.4
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**2.2) % 1.1) * (x ** 2.3)
            score += base_score + extra_sum / 6
            if score > 16:
                score -= 3
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 2) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 2:
                score += 15 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -4:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 18:
                score /= 2.5
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 12):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.7) * np.cos(p)
                if abs(penalty_base) > 60:
                    penalty_base = np.log1p(abs(penalty_base)) * np.sign(penalty_base)
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 8 == 0):
                score -= 7
            if score < -5:
                score *= -1.3
                score += 6
            if score > 120:
                score = 120
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 2.9) / (q + 2) * np.sin(q + diff)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 3 == 0):
                score -= 9
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.4) * np.cos(r * diff)
                if abs(term) > 15000:
                    term = np.sqrt(abs(term)) * np.sign(term)
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2500:
                score = 2500
        if capacity > 150:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.5
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
